import { useState, useEffect, useRef } from "react";

const VIDEO_SRC = "data:video/mp4;base64,";


const SYSTEM_PROMPT = `你是一位熟讀《幼兒園教保活動課程：幼兒學習評量手冊》的 AI 評量夥伴，代號「RF 評量精靈」。
工作：協助幼教老師根據觀察到的幼兒真實行為，找出最合適的「核心素養評量指標」與「等級（1-4）」。

【說話風格】親切溫暖，像貼心同事。老師很辛苦，多給肯定。不說空話，每句都有幫助。

【評量等級精神（來自手冊）】
等級1：萌芽探索，需成人引導｜等級2：發展中，能部分達到｜等級3：獨立穩定，單一情境達成｜等級4：延伸應用，跨情境靈活

【最重要的規定】
1. 若描述少於35字或缺乏具體情境/對話/行為，絕對不猜測，用溫暖語氣追問最關鍵的一個問題
2. 追問時說明為何需要這個細節
3. 評分必須引用老師原本描述的內容對應等級規準

【輸出】嚴格回傳 JSON（無 markdown）：
{ "needMoreInfo": bool, "question": "追問（needMoreInfo為true）", "encouragement": "給老師的暖心話（每次都要有）", "result": { "competence": "核心素養", "indicatorName": "指標名稱", "level": 數字, "levelDesc": "該等級規準", "whyThisLevel": "引用描述說明", "scaffold": "具體鷹架建議" } }`;

const INDICATORS = {
  "覺知辨識": [
    { name:"覺察自己及他人的特徵與興趣，並能比較異同", levels:["知道自己或他人外在穩定的特徵或興趣","知道自己及他人的特徵或興趣，但尚未比較異同","知道且能比較自己及他人特徵或興趣的異同","知道且能比較異同，也知道興趣會因情境而有所變化並說明理由"] },
    { name:"覺察自己及他人的想法或情感，並能比較異同", levels:["知道自己或他人外在明顯的想法或情感","知道自己及他人的想法或情感，但尚未比較","知道且能比較自己及他人想法或情感的異同","能比較異同，且知道情感會因情境不同而變化"] },
    { name:"知道生活規範及活動規則的理由", levels:["在提醒下能說出常見規範或規則","主動說出常見規範或規則，但未說明理由","能說出規範背後的表面理由","能說出保護自己或他人的深層理由"] },
    { name:"理解口語的意義", levels:["聽懂包含單一指令的簡單句子","聽懂包含兩個相關指令的句子","聽懂敘述事件或因果關係的複雜句子","聽懂言外之意或帶有隱喻推論性質的話語"] },
    { name:"注意且理解周遭的自然現象訊息", levels:["注意到動植物或自然現象的明顯特徵","描述動植物外型或自然現象的變化過程","找出動植物或自然現象之間的關聯性","預測自然現象的變化或理解對生活的影響"] }
  ],
  "表達溝通": [
    { name:"運用視覺藝術素材表達想法或情感", levels:["隨意塗鴉或把玩素材，尚未賦予特定意義","創作後為作品命名或做簡單描述","有計畫地運用視覺素材表達特定想法或情感","綜合運用多種素材細膩表達複雜感受並分享理念"] },
    { name:"運用口語表達想法或情感", levels:["用單字或簡短句子表達基本需求或情緒","用完整句子描述當下的發現或感受","有條理地敘述事件並清楚表達觀點","因應聽眾或情境調整語氣音量與內容深度"] },
    { name:"在對話情境中相互表達、傾聽、協商，並調整想法", levels:["多以表達自己意見為主，較少回應他人","能輪流說話並簡單回應他人","專注傾聽並針對對方內容提出相關回應","能協商妥協調整自己想法以達成共識"] }
  ],
  "關懷合作": [
    { name:"理解他人之需求，表現利社會的行為", levels:["在成人提醒下做出分享或協助等友善行為","覺察同伴明顯需求並主動給予簡單幫助","理解同伴困難並提供具體有效的協助","敏銳察覺弱勢者需求並主動倡導或號召關懷"] },
    { name:"與他人合作完成工作或解決問題", levels:["與同伴在同一空間平行遊戲偶爾共用素材","與同伴簡單合作但分工不明確","討論並分配工作共同朝向目標完成任務","協調不同意見並主動支援帶領團隊解決問題"] }
  ],
  "推理賞析": [
    { name:"依據特徵整理生活環境中的訊息並找出特徵間的關係", levels:["依據單一明顯特徵將物品分類或配對","依據兩個以上特徵分類或排出序列","找出事物間的關聯性並完成規則性排列","發現隱含的複雜規則並應用規則預測或創造"] },
    { name:"分析已知的訊息找出形成特定現象的原因", levels:["觀察到現象改變但無法連結原因","在提示下猜測造成現象的直接原因","主動根據觀察線索推論可能原因","透過簡單實驗驗證對現象原因的推論"] },
    { name:"欣賞及回應自己及他人的表現", levels:["專注觀看他人作品給予簡單情緒反應","說出喜歡或不喜歡某作品的直觀感受","具體指出作品中吸引人的細節","提出獨到賞析觀點並以正向具體方式給予建議"] }
  ],
  "想像創造": [
    { name:"透過戲劇扮演進行想像創作", levels:["模仿單一生活動作","運用道具扮演熟悉角色並做出相關行為","與同伴共同設定情境分配角色發展有情節的扮演遊戲","加入天馬行空想像創造非現實角色或曲折故事情節"] },
    { name:"進行敘事文本的想像創作", levels:["接續大人說了一半的故事說出下一個動作","改變熟悉故事的某個角色或結局","根據圖片或開頭編創有邏輯連貫性的短故事","融合多種元素創作具備高潮起伏與豐富細節的完整原創故事"] }
  ],
  "自主管理": [
    { name:"協調及控制大肌肉，完成肢體動作活動", levels:["平穩進行走跑跳等基本移動動作","操控簡單器材進行單一動作","靈活變換動作方向與速度完成挑戰性任務","精熟掌控大肌肉動作並主動調整力道與安全距離"] },
    { name:"協調及控制小肌肉，完成精細動作活動", levels:["用抓握動作操作大塊教具","用手指捏扭轉等動作操作一般教具","熟練運用剪刀畫筆等工具完成手眼協調任務","極精準操控微小素材展現高度手部靈活度"] },
    { name:"調整自己的想法、情緒或行為，以符合規範", levels:["在成人反覆引導下稍微克制衝動","經提醒後配合團體規範調整行為","主動覺察情境要求運用策略自行調整情緒","高度自律能理性表達並引導同伴遵守規範"] }
  ]
};

export default function App() {
  const [phase, setPhase] = useState("splash");
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [age, setAge] = useState("");
  const [activity, setActivity] = useState("");
  const [history, setHistory] = useState([]);
  const [feedbackOpen, setFeedbackOpen] = useState(false);
  const [fpComp, setFpComp] = useState("");
  const [fpReason, setFpReason] = useState("");
  const [feedbackCount, setFeedbackCount] = useState(0);
  const bottomRef = useRef(null);
  const videoRef = useRef(null);

  useEffect(() => {
    if (phase === "chat" && messages.length === 0) {
      setMessages([{ role:"bot", type:"welcome", text:"老師您好！我是 RF 評量精靈 ✨\n\n知道您每天觀察那麼多孩子還要寫評量，真的很辛苦。讓我來幫您！\n\n請告訴我您觀察到的情況，越具體越好——孩子說了什麼？做了什麼？跟誰互動？我會幫您找出最合適的評量指標和等級。" }]);
    }
  }, [phase]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior:"smooth" });
  }, [messages, loading]);

  const handleVideoEnd = () => {
    setPhase("fade");
    setTimeout(() => setPhase("chat"), 600);
  };

  const callAPI = async (userText) => {
    const ctx = (age || activity) ? `【幼兒：${age||"未填"} ／ ${activity||"未填"}活動】\n` : "";
    const newHistory = [...history, { role:"user", content: ctx + userText }];
    setHistory(newHistory);
    const resp = await fetch("https://api.anthropic.com/v1/messages", {
      method:"POST",
      headers:{ "Content-Type":"application/json" },
      body:JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:1000, system:SYSTEM_PROMPT, messages:newHistory })
    });
    const data = await resp.json();
    const raw = data.content?.[0]?.text?.trim() || "";
    setHistory(h => [...h, { role:"assistant", content:raw }]);
    return raw;
  };

  const handleSend = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput("");
    setMessages(m => [...m, { role:"user", text }]);
    setLoading(true);
    try {
      const raw = await callAPI(text);
      let parsed = null;
      try { parsed = JSON.parse(raw.replace(/```json|```/g,"").trim()); } catch(e) {}
      if (parsed?.needMoreInfo) {
        setMessages(m => [...m, { role:"bot", text:(parsed.encouragement ? parsed.encouragement+"\n\n" : "")+parsed.question }]);
      } else if (parsed?.result) {
        setMessages(m => [...m, { role:"bot", type:"result", encouragement:parsed.encouragement, result:parsed.result }]);
      } else {
        setMessages(m => [...m, { role:"bot", text:raw }]);
      }
    } catch(e) {
      setMessages(m => [...m, { role:"bot", text:"連線發生問題，請稍後再試一次。" }]);
    }
    setLoading(false);
  };

  const submitFeedback = () => {
    if (!fpComp || !fpReason.trim()) return;
    setFeedbackCount(c => c+1);
    setMessages(m => [...m, { role:"bot", text:`謝謝您的回饋！您認為「${fpComp}」更合適。\n\n這個意見我已記下，會幫助我越來越準確 ☺` }]);
    setFeedbackOpen(false); setFpComp(""); setFpReason("");
  };

  const quickPrompts = ["角色扮演情境","自然觀察描述","合作解決問題","情緒調節表現","創作與表達"];

  const BotAvatar = () => (
    <div style={{width:26,height:26,borderRadius:"50%",background:"#1a1a1a",border:"1px solid #2e2e2e",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,marginTop:2}}>
      <span style={{fontSize:8,color:"#e5c97e",fontWeight:700,letterSpacing:0.5}}>RF</span>
    </div>
  );

  if (phase === "splash" || phase === "fade") return (
    <div style={{position:"fixed",inset:0,background:"#000",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",transition:"opacity 0.6s",opacity:phase==="fade"?0:1}}>
      <video ref={videoRef} src={VIDEO_SRC} autoPlay muted playsInline onEnded={handleVideoEnd}
        style={{maxWidth:280,maxHeight:280,objectFit:"contain"}} />
      <p style={{color:"#2a2a2a",fontSize:11,marginTop:28,letterSpacing:5,fontFamily:"monospace",textTransform:"uppercase"}}>RF Education Tools</p>
    </div>
  );

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100vh",background:"#0a0a0a",color:"#e0e0e0",fontFamily:"'Noto Sans TC',sans-serif"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+TC:wght@300;400;500&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:3px}::-webkit-scrollbar-thumb{background:#2a2a2a;border-radius:3px}
        textarea,select,button{font-family:inherit;outline:none}
        textarea{resize:none}
        @keyframes fadeUp{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
        @keyframes blink{0%,100%{opacity:0.2}50%{opacity:1}}
        .msg-in{animation:fadeUp 0.25s ease}
        .chip-btn:hover{background:#1e1e1e!important;border-color:#e5c97e!important;color:#e5c97e!important}
        .send-btn:hover:not(:disabled){background:#c9a84c!important}
        .send-btn:disabled{opacity:0.3;cursor:not-allowed}
        .fb-link:hover{color:#e5c97e!important}
      `}</style>

      <div style={{padding:"11px 16px",borderBottom:"1px solid #181818",display:"flex",alignItems:"center",gap:10,background:"#0a0a0a",flexShrink:0}}>
        <div style={{width:34,height:34,borderRadius:"50%",background:"#111",border:"1px solid #2a2a2a",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
          <span style={{fontSize:11,color:"#e5c97e",fontWeight:700,letterSpacing:1}}>RF</span>
        </div>
        <div style={{flex:1}}>
          <p style={{fontSize:13,fontWeight:500,color:"#e0e0e0"}}>RF 評量精靈</p>
          <p style={{fontSize:11,color:"#3a3a3a"}}>依據《幼兒學習評量手冊》· 六大核心素養</p>
        </div>
        <div style={{fontSize:11,color:"#3a3a3a",textAlign:"right"}}>
          回饋 <span style={{color:"#e5c97e"}}>{feedbackCount}</span> 筆
        </div>
      </div>

      <div style={{padding:"7px 12px",borderBottom:"1px solid #141414",display:"flex",gap:6,background:"#0a0a0a",flexShrink:0}}>
        {[
          ["age", age, setAge, ["幼幼班(2-3歲)","小班(3-4歲)","中班(4-5歲)","大班(5-6歲)"], "選擇年齡"],
          ["act", activity, setActivity, ["學習區","團體活動","例行性活動","戶外活動","全園性活動"], "選擇活動"]
        ].map(([k,val,setter,opts,ph]) => (
          <select key={k} value={val} onChange={e=>setter(e.target.value)}
            style={{flex:1,minWidth:0,fontSize:12,padding:"5px 8px",background:"#141414",border:"1px solid #222",borderRadius:6,color:val?"#c0c0c0":"#444",cursor:"pointer"}}>
            <option value="">{ph}</option>
            {opts.map(o=><option key={o} value={o}>{o}</option>)}
          </select>
        ))}
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"14px 12px",display:"flex",flexDirection:"column",gap:10}}>
        {messages.map((msg,i) => (
          <div key={i} className="msg-in" style={{display:"flex",gap:8,maxWidth:"88%",alignSelf:msg.role==="user"?"flex-end":"flex-start",flexDirection:msg.role==="user"?"row-reverse":"row"}}>
            {msg.role==="bot" && <BotAvatar/>}
            <div style={{flex:1}}>
              {msg.type==="result" ? (
                <div style={{background:"#111",border:"1px solid #1e1e1e",borderRadius:12,padding:14,fontSize:13}}>
                  {msg.encouragement && <p style={{color:"#666",fontSize:12,lineHeight:1.7,marginBottom:10,paddingBottom:10,borderBottom:"1px solid #1a1a1a"}}>{msg.encouragement}</p>}
                  <span style={{display:"inline-block",fontSize:11,padding:"2px 9px",borderRadius:20,background:"#1a1a00",border:"1px solid #3a3000",color:"#e5c97e",marginBottom:8}}>{msg.result.competence}</span>
                  <p style={{fontSize:13,fontWeight:500,color:"#e0e0e0",lineHeight:1.5,marginBottom:10}}>{msg.result.indicatorName}</p>
                  <div style={{display:"flex",gap:5,marginBottom:10}}>
                    {[1,2,3,4].map(n=>(
                      <div key={n} style={{padding:"3px 10px",borderRadius:20,fontSize:12,border:n===msg.result.level?"1px solid #e5c97e":"1px solid #222",background:n===msg.result.level?"#1e1800":"transparent",color:n===msg.result.level?"#e5c97e":"#444"}}>
                        {n} 級
                      </div>
                    ))}
                  </div>
                  {[["等級規準", msg.result.levelDesc],["判斷依據", msg.result.whyThisLevel],["教學鷹架建議", msg.result.scaffold]].map(([label,text])=>(
                    <div key={label} style={{borderTop:"1px solid #181818",paddingTop:8,marginTop:8}}>
                      <p style={{fontSize:10,color:"#444",marginBottom:4,textTransform:"uppercase",letterSpacing:"0.08em"}}>{label}</p>
                      <p style={{fontSize:12,color:"#aaa",lineHeight:1.7}}>{text}</p>
                    </div>
                  ))}
                  <button onClick={()=>setFeedbackOpen(f=>!f)} className="fb-link"
                    style={{marginTop:10,fontSize:11,color:"#444",background:"transparent",border:"none",padding:0,cursor:"pointer",transition:"color 0.15s"}}>
                    指標不合適？點此提供回饋 →
                  </button>
                </div>
              ) : (
                <div style={{padding:"10px 14px",borderRadius:msg.role==="user"?"12px 4px 12px 12px":"4px 12px 12px 12px",fontSize:13,lineHeight:1.75,whiteSpace:"pre-wrap",background:msg.role==="user"?"#1a1a1a":"#111",border:msg.role==="user"?"1px solid #222":"1px solid #181818",color:msg.role==="user"?"#ddd":"#bbb"}}>
                  {msg.text}
                  {msg.type==="welcome" && (
                    <div style={{marginTop:12,display:"flex",flexWrap:"wrap",gap:6}}>
                      {quickPrompts.map(p=>(
                        <button key={p} className="chip-btn" onClick={()=>setInput(`我想描述關於「${p}」的幼兒觀察，`)}
                          style={{fontSize:11,padding:"3px 10px",background:"#141414",border:"1px solid #222",borderRadius:20,color:"#555",cursor:"pointer",transition:"all 0.15s"}}>
                          {p}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        ))}
        {loading && (
          <div style={{display:"flex",gap:8,alignSelf:"flex-start"}} className="msg-in">
            <BotAvatar/>
            <div style={{padding:"12px 16px",background:"#111",border:"1px solid #181818",borderRadius:"4px 12px 12px 12px",display:"flex",gap:5,alignItems:"center"}}>
              {[0,1,2].map(n=><span key={n} style={{width:5,height:5,borderRadius:"50%",background:"#e5c97e",display:"inline-block",animation:`blink 1.2s ease ${n*0.2}s infinite`}}/>)}
            </div>
          </div>
        )}
        <div ref={bottomRef}/>
      </div>

      {feedbackOpen && (
        <div style={{padding:"12px 14px",borderTop:"1px solid #181818",background:"#0e0e0e",flexShrink:0}}>
          <p style={{fontSize:12,color:"#666",marginBottom:8}}>您覺得哪個核心素養更合適？</p>
          <select value={fpComp} onChange={e=>setFpComp(e.target.value)}
            style={{width:"100%",fontSize:12,padding:"6px 8px",background:"#141414",border:"1px solid #222",borderRadius:6,color:fpComp?"#ccc":"#444",marginBottom:6}}>
            <option value="">選擇更合適的核心素養</option>
            {Object.keys(INDICATORS).map(k=><option key={k} value={k}>{k}</option>)}
          </select>
          <textarea value={fpReason} onChange={e=>setFpReason(e.target.value)} placeholder="請說明原因，幫助 AI 持續學習改進..."
            style={{width:"100%",fontSize:12,padding:"7px 10px",background:"#141414",border:"1px solid #222",borderRadius:6,color:"#ccc",height:52,marginBottom:6}}/>
          <div style={{display:"flex",gap:6}}>
            <button onClick={submitFeedback} style={{fontSize:12,padding:"5px 16px",background:"#e5c97e",border:"none",borderRadius:6,color:"#000",fontWeight:500}}>送出回饋</button>
            <button onClick={()=>setFeedbackOpen(false)} style={{fontSize:12,padding:"5px 12px",background:"transparent",border:"1px solid #222",borderRadius:6,color:"#555"}}>取消</button>
          </div>
        </div>
      )}

      <div style={{padding:"10px 12px",borderTop:"1px solid #141414",display:"flex",gap:8,background:"#0a0a0a",flexShrink:0}}>
        <textarea value={input} onChange={e=>setInput(e.target.value)}
          onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handleSend()}}}
          placeholder="描述您觀察到的幼兒行為... (Enter 送出，Shift+Enter 換行)"
          style={{flex:1,background:"#141414",border:"1px solid #202020",borderRadius:10,padding:"9px 12px",fontSize:13,color:"#e0e0e0",height:68,lineHeight:1.6}}/>
        <button onClick={handleSend} disabled={loading} className="send-btn"
          style={{width:42,height:42,borderRadius:"50%",background:"#e5c97e",border:"none",alignSelf:"flex-end",display:"flex",alignItems:"center",justifyContent:"center",transition:"background 0.15s",cursor:"pointer"}}>
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#000" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
          </svg>
        </button>
      </div>
    </div>
  );
}
